+    #[derive(Debug)]
+    struct RebuildDrainScheduleSummary {
+        total_spin_loops: u64,
+        max_spin_loops: u32,
+        yield_count: u32,
+        p95_spin_loops: u32,
+        full_scan_interval: Duration,
+    }
